def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        priority = 0.0
        risk_factor = 1.0
        complexity = 0.0
        boost = 1.0
        decay = 1.0
        base_score = np.log1p(item + cap) * np.sqrt(cap)
        for a in range(1, 15):
            for b in range(1, 7):
                val = (item * a) / (cap + b)
                if val > 1:
                    complexity += np.exp(-val + a / (b + 1))
                else:
                    complexity -= np.cos(val * np.pi * b) / (a + b)
                if (cap + a*b) % 5 == 0:
                    risk_factor *= 0.97 + 0.01 * (a % 3)
                elif (item * b - a) % 4 == 0:
                    risk_factor *= 1.03 - 0.005 * (b % 2)
                if b == 3 and a % 2 == 0:
                    boost += np.tanh(val) / (a + 1)
                if b == 5:
                    decay *= 0.95 + 0.02 * np.sin(val * np.pi / (a + 1))
            if a % 4 == 1:
                priority += (a**1.5) / (1 + np.exp(-item / (cap + a)))
            else:
                priority += (np.log1p(a*b) + complexity) * risk_factor / (a + decay)
            if cap % (a + 2) == 0:
                priority += np.sin(priority + complexity) * 0.1
        penalty = 0.0
        for c in range(1, 8):
            diff = cap - item * c**1.1
            if diff > 0:
                if diff % (c + 3) == 0:
                    penalty += np.sqrt(diff) / (c + 1)
                else:
                    penalty -= np.log1p(abs(diff)) / (c + 4)
            else:
                penalty -= abs(diff)**1.2 / (c + 2)
        priority = (priority + penalty) * boost / (1 + decay)
        if priority < 0:
            priorities[idx] = -priority * np.exp(-item / (cap + 1))
        else:
            if cap > 3 * item:
                priorities[idx] = -priority / (np.sqrt(cap) + 1) * (1 + item / cap)**2
            else:
                priorities[idx] = -priority / (cap + 4) * np.exp(- (item / cap)**3)
        if (cap + idx) % 3 == 0:
            priorities[idx] *= 1.07
        elif (item * (idx + 1)) % 4 == 0:
            priorities[idx] *= 0.92
        if cap % 2 == 1 and item > cap / 2:
            priorities[idx] *= 1.12 - 0.01 * idx
        else:
            priorities[idx] *= 0.94 + 0.005 * idx
    return priorities
